command:
mkdir -p space && printf 'metrics:
  - {id: space-perf-rubric-pass-rate, dimension: performance, value: 0.85}
' > space/metrics.yaml && printf 'dimensions:
  performance: {enabled: true}
share: never
' > space/config.yaml && bash "$CLAUDE_PLUGIN_ROOT/commands/space-report.sh" --metrics space/metrics.yaml --config space/config.yaml 2>out.txt && grep -q 'space-perf-rubric-pass-rate' out.txt && grep -q '0.85' out.txt && echo ok 1>&2
